export const PREBUILT_PROMPTS: Record<string, Array<{ id: string; title: string; description: string; prompt: string }>> = {
  "Office & Work": [
    { id: "o1", title: "Write a Professional Email", description: "Draft clear, polished emails for any work situation.", prompt: "Help me write a professional email. Tell me who the recipient is (manager, client, colleague, vendor), the purpose of the email (request, follow-up, apology, update, complaint, introduction), and the key points I want to convey. Then write a concise, polished email with a strong subject line, clear body, and appropriate closing." },
    { id: "o2", title: "Prepare a Meeting Agenda", description: "Structure a productive meeting in minutes.", prompt: "Help me prepare a meeting agenda. Ask me about the meeting's purpose, who will attend, how long the meeting is, and the key topics or decisions that need to be covered. Then create a clear, time-boxed agenda that keeps the meeting focused and productive, and suggest 2 tips to run the meeting effectively." },
    { id: "o3", title: "Write a Project Status Report", description: "Communicate project updates clearly to stakeholders.", prompt: "Help me write a concise project status report. Ask me about the project name, current phase, what was accomplished this week, what's planned for next week, any blockers or risks, and the overall project health (on track, at risk, delayed). Then write a professional status report I can share with my team or manager." },
    { id: "o4", title: "Handle a Difficult Colleague", description: "Navigate workplace conflict professionally.", prompt: "I'm having a conflict with a colleague at work. Act as a workplace communication coach. Ask me to describe the situation — what happened, how it affected my work, and what I've already tried. Then help me understand the situation from both sides, suggest how to approach a constructive conversation, and give me specific phrases I can use to resolve the issue professionally." },
    { id: "o5", title: "Write Performance Review Comments", description: "Write strong self-review or peer review comments.", prompt: "Help me write performance review comments. Ask me whether this is a self-review or peer review, the role of the person being reviewed, 3–5 key achievements or contributions, any areas for improvement, and the overall tone I want (encouraging, constructive, formal). Then write polished, specific, and impactful review comments." },
    { id: "o6", title: "Summarize a Long Document", description: "Extract key insights from any work document fast.", prompt: "I have a long document or report I need to summarize. I'll paste the content or describe it. Provide: 1) A 3-sentence executive summary, 2) The 5 most important findings or points, 3) Any recommended actions or decisions, and 4) One critical thing a decision-maker should know. Keep the summary clear and concise." },
    { id: "o7", title: "Prepare a Presentation Outline", description: "Structure a compelling deck for any audience.", prompt: "Help me prepare an outline for a professional presentation. Ask me about the topic, the audience (team, clients, leadership, investors), the goal of the presentation (inform, persuade, update, pitch), and the time available. Then create a clear slide-by-slide outline with a suggested title and 2–3 bullet points per slide." },
    { id: "o8", title: "Create a Task Priority List", description: "Organize your workload using proven frameworks.", prompt: "Help me prioritize my work tasks. I'll share a list of tasks I need to complete. Use the Eisenhower Matrix (urgent vs important) to categorize them, then suggest the order I should tackle them in, which tasks I can delegate or drop, and a simple focus plan for the day." },
    { id: "o9", title: "Write a Proposal or Business Case", description: "Make a compelling case for your idea or project.", prompt: "Help me write a business case or proposal. Ask me what I'm proposing, who the decision-makers are, the problem it solves, the expected benefits, estimated cost or resources required, and the timeline. Then write a structured business case with an executive summary, problem statement, proposed solution, benefits, risks, and a clear call to action." },
    { id: "o10", title: "Improve My Work Communication", description: "Sound more confident and professional at work.", prompt: "Act as a workplace communication coach. Ask me about a specific communication challenge I face at work — such as speaking up in meetings, giving feedback to a peer, saying no to extra work, presenting to leadership, or writing assertive emails. Then give me practical tips, a reframing strategy, and 3 specific phrases I can start using immediately." },
    { id: "o11", title: "Draft Meeting Minutes", description: "Turn rough notes into professional meeting minutes.", prompt: "Help me write clean meeting minutes. I'll share rough notes or a summary of what was discussed. Organize them into: Meeting title and date, Attendees, Key discussion points, Decisions made, Action items with owners and deadlines, and Next steps. Keep the language clear, professional, and easy to scan." },
    { id: "o12", title: "Write a LinkedIn Post for Work Wins", description: "Share your professional achievements with your network.", prompt: "Help me write a LinkedIn post about a recent work achievement or milestone. Ask me what the achievement is, the impact it had, who was involved, and the tone I want. Then write a compelling LinkedIn post that tells a brief story, highlights the achievement naturally, and ends with a thoughtful insight or takeaway." },
    { id: "o13", title: "Write an Escalation Email", description: "Communicate critical issues to leadership effectively.", prompt: "I need to escalate an issue at work via email. Ask me what the issue is, who I'm escalating to, what I've already tried to resolve it, and the urgency level. Then write a firm but professional escalation email that clearly explains the problem, the impact, what's been done, and what I need the recipient to do." },
    { id: "o14", title: "Prepare for a Difficult Conversation", description: "Frameworks and scripts for tough workplace talks.", prompt: "Help me prepare for a difficult conversation at work. Ask me who the conversation is with, what the issue is, what outcome I want, and what I'm nervous about. Then give me a step-by-step conversation framework, 3 opening lines to start calmly, and advice on how to handle common defensive reactions." },
    { id: "o15", title: "Write an OOO / Leave Email", description: "Set clear expectations while you are away.", prompt: "Help me write an out-of-office email message. Ask me my leave dates, reason for absence (optional), who to contact in my absence, and the tone I want (formal or friendly). Then write a professional and complete OOO message I can set up in my email client." },
    { id: "o16", title: "Create a Weekly Work Plan", description: "Structure your week for maximum productivity.", prompt: "Help me plan my work week effectively. I'll share my key responsibilities, pending tasks, upcoming meetings, and deadlines. Then help me create a structured weekly plan that batches similar tasks, protects focus time, balances urgent vs important work, and includes a simple end-of-day wrap-up habit." },
    { id: "o17", title: "Write a Thank You Email After a Meeting", description: "Follow up and confirm next steps after any meeting.", prompt: "Help me write a professional thank you email to send after a meeting. Ask me who the meeting was with, the purpose of the meeting, the key outcomes or decisions made, and any next steps I'm responsible for. Then write a warm, concise follow-up email that recaps the highlights and confirms next steps." },
    { id: "o18", title: "Respond to a Negative Feedback Email", description: "Handle criticism with grace and professionalism.", prompt: "I received critical or negative feedback at work and need to respond professionally. Ask me what the feedback was about, who sent it, whether it's fair or not, and the outcome I want from my reply. Then write a composed, professional response that acknowledges the concern, addresses it clearly, and keeps the relationship intact." },
    { id: "o19", title: "Write a Job Description", description: "Attract the right talent with clear role definitions.", prompt: "Help me write a job description. Ask me about the role title, key responsibilities, required skills and qualifications, preferred experience, team structure, and any perks or culture highlights. Then write a clear, engaging job description that attracts the right candidates and reflects the role accurately." },
    { id: "o20", title: "Give Constructive Feedback", description: "Deliver honest feedback that drives growth.", prompt: "Help me give constructive feedback to a colleague or team member. Ask me what the feedback is about, the person's role, my relationship with them, whether the issue is recurring, and the outcome I want. Then help me frame the feedback using the SBI model (Situation, Behavior, Impact) with exact phrases that are honest but supportive." },
    { id: "o21", title: "Write a Client Update Email", description: "Keep your clients informed and trust high.", prompt: "Help me write a client update email. Ask me the project or service involved, what progress has been made, any delays or changes, the next steps, and the tone I want. Then write a clear, professional client update email that keeps trust high and expectations aligned." },
    { id: "o22", title: "Create an Onboarding Plan", description: "Set new hires up for success from day one.", prompt: "Help me create an onboarding plan for a new team member. Ask me the role, team size, tools and systems they'll use, key people they need to meet, and how long the onboarding should take. Then create a structured onboarding plan with daily/weekly milestones, key learning objectives, and a checklist for the first 30 days." },
  ],
  "Personal": [
    { id: "p1", title: "Daily Reflection Journal", description: "Reflect on your day with guided prompts.", prompt: "Act as a thoughtful journaling coach. Ask me 5 deep but simple questions to help me reflect on my day — what went well, what I could improve, how I felt emotionally, one thing I'm grateful for, and one intention I want to set for tomorrow. Keep the tone warm and non-judgmental." },
    { id: "p2", title: "Build a Morning Routine", description: "Design a personalized morning routine.", prompt: "Help me design an ideal morning routine based on my lifestyle. Ask me about my wake-up time, goals (fitness, focus, calm), available time, and any current habits. Then create a step-by-step morning routine that's realistic, energizing, and tailored to me." },
    { id: "p3", title: "Overcome Procrastination", description: "Get unstuck and start taking action.", prompt: "I've been procrastinating on a task. Help me break through it. Ask me what the task is, why I think I'm avoiding it, and how I feel about it. Then give me a simple action plan to get started in the next 10 minutes using techniques like the 2-minute rule or task chunking." },
    { id: "p4", title: "Manage Stress & Anxiety", description: "Get practical advice for calming your mind.", prompt: "I'm feeling stressed and overwhelmed. Act as a calm, supportive wellness coach. Help me identify the main source of my stress, reframe my thoughts around it, and suggest 3 practical techniques I can use right now to feel calmer and more in control." },
    { id: "p5", title: "Personal Life Audit", description: "Evaluate your life and reset your direction.", prompt: "Act as a life and career advisor and help me conduct a personal life audit. First ask me 7 deep questions about my goals, interests, values, personality, how I spend my time, what motivates me, and what kind of life or career I want to build. Ask the questions one at a time. After collecting my answers, tell me where I might be wasting time or energy, what skills to build in the next 6 months, what career paths might fit my personality, and one habit holding me back with advice on how to fix it." },
    { id: "p6", title: "Analyze an Important Decision", description: "Think through complex choices with strategic analysis.", prompt: "Help me think through an important decision I am currently confused about. First ask me about the decision, my options, the context, and any constraints or risks. Then analyze the decision by explaining the best case scenario, worst case scenario, hidden risks, and long-term consequences. Finally suggest logical next steps to make a strategic decision." },
    { id: "p7", title: "Build a Self-Care Routine", description: "Create a sustainable plan for your wellbeing.", prompt: "Help me build a realistic self-care routine. Ask me about my lifestyle, how much free time I have per day, my biggest source of stress, and what helps me feel recharged. Then create a simple daily and weekly self-care plan covering physical, mental, and emotional wellbeing — one I can actually stick to." },
    { id: "p8", title: "Write a Personal Vision Statement", description: "Define your values and long-term life direction.", prompt: "Help me write a personal vision statement. Ask me about my deepest values, the kind of person I want to become, the impact I want to have on others, and what a fulfilling life looks like to me. Then write a powerful personal vision statement in 3–5 sentences that I can revisit every day to stay aligned with my goals." },
    { id: "p9", title: "Overcome Fear of Failure", description: "Reframe failure and take bold action today.", prompt: "I'm struggling with a fear of failure that's holding me back. Act as a mindset coach. Ask me what I'm afraid of failing at and why it matters so much. Then help me reframe my relationship with failure using real examples and psychological insights, and give me a practical 3-step exercise to take one bold action despite the fear." },
    { id: "p10", title: "Create a Digital Detox Plan", description: "Reset your relationship with technology and focus.", prompt: "Help me create a digital detox plan. Ask me how many hours I spend on my phone daily, which apps consume most of my time, what I wish I could do instead, and whether I want a full detox or gradual one. Then create a realistic 7-day digital detox plan with daily limits, replacement habits, and tips to deal with urges." },
    { id: "p11", title: "Improve Your Sleep Quality", description: "Science-backed habits for better rest and energy.", prompt: "Help me improve my sleep quality. Ask me about my current sleep schedule, how long it takes me to fall asleep, what disrupts my sleep, my screen habits before bed, and how I feel when I wake up. Then give me a science-backed 2-week sleep improvement plan including a bedtime routine, environment tweaks, and habits to avoid." },
    { id: "p12", title: "Build Unshakeable Confidence", description: "Exercises and mindset shifts for self-assurance.", prompt: "Help me build real confidence. Act as a mindset and confidence coach. Ask me what areas of my life I feel least confident in, where my self-doubt usually shows up, and what confident people around me seem to do differently. Then give me a 21-day confidence-building plan with daily exercises, a journaling practice, and specific mindset shifts to internalize." },
    { id: "p13", title: "Write a Letter to Your Future Self", description: "Capture your current self for your future journey.", prompt: "Help me write a meaningful letter to my future self — to be read 5 years from now. Ask me about my current life situation, what I'm proud of today, what I'm struggling with, my biggest dreams, and what I hope will have changed in 5 years. Then write a heartfelt, honest letter in first person that I'll be moved to read in the future." },
    { id: "p14", title: "Design a Healthy Eating Plan", description: "A realistic 7-day plan tailored to your goals.", prompt: "Help me design a realistic healthy eating plan. Ask me about my dietary preferences or restrictions, my health goal (weight loss, energy, muscle gain, general wellness), how much time I can spend cooking, my budget, and how many meals per day I prefer. Then create a 7-day meal plan with breakfast, lunch, dinner, and one snack per day — simple, nutritious, and easy to prepare." },
    { id: "p15", title: "Create a 30-Day Fitness Challenge", description: "Progressive workout plan for any fitness level.", prompt: "Help me create a 30-day fitness challenge. Ask me about my current fitness level (beginner, intermediate, active), my goal (weight loss, strength, endurance, flexibility), how many days per week I can work out, available equipment (none, dumbbells, gym), and any injuries or limitations. Then build a progressive 30-day workout plan with specific exercises, sets, and rest days." },
  ],
  "Career": [
    { id: "c1", title: "Craft a Standout Resume", description: "Get tailored resume writing help.", prompt: "Act as a professional resume coach. I'll share my job title, experience, and the role I'm applying for. Help me rewrite my resume bullet points using strong action verbs and quantifiable results. Make it ATS-friendly and tailored to the job description I provide." },
    { id: "c2", title: "Ace Your Job Interview", description: "Prepare confident answers to tough questions.", prompt: "I have a job interview coming up. Act as an interview coach. Ask me the role I'm applying for and 3 questions I'm nervous about. Then help me craft strong, structured answers using the STAR method. Also give me 2 smart questions I can ask the interviewer." },
    { id: "c3", title: "Write a LinkedIn Summary", description: "Create a compelling LinkedIn profile bio.", prompt: "Help me write a compelling LinkedIn 'About' section. Ask me about my current role, years of experience, key skills, biggest achievements, and what kind of opportunities I'm seeking. Then write a professional, engaging summary in first person that highlights my value and ends with a clear call to action." },
    { id: "c4", title: "Negotiate Your Salary", description: "Get scripts and strategies to negotiate confidently.", prompt: "I want to negotiate a higher salary. Act as a negotiation coach. Ask me my current offer, target salary, experience level, and the industry. Then give me a word-for-word script I can use to negotiate confidently, along with tips to handle common pushback from employers." },
    { id: "c5", title: "Prepare for an Interview", description: "Comprehensive prep for any role or company.", prompt: "I am appearing for an interview. Act as a research analyst and interview preparation coach. First ask me the company, role, industry, and my experience level. Generate 10 likely interview questions, 5 behavioral questions, and 3 case study or situation-based questions. For each question, explain what the interviewer is evaluating and how I should structure my answer for maximum impact." },
    { id: "c6", title: "Mock Interview Practice", description: "Practice answering tough questions with feedback.", prompt: "Act as an interviewer and conduct a mock interview for me. First ask me about the role, company, and industry. Then ask me 5 challenging interview questions one at a time. After each answer, give clear feedback on what I did well, where I can improve, and how to structure a stronger response." },
    { id: "c7", title: "Research a Company", description: "Get a deep dive into any company's culture and model.", prompt: "Act as a research analyst and help me prepare a detailed research brief about a company. Ask me which company, the role I'm interested in, and the context. Create a structured brief covering: company overview, business model, products/services, key competitors, recent news, work culture, salary range, and key skills valued. Finally suggest 3 smart questions I can ask the interviewer." },
    { id: "c8", title: "Career Gap Analysis", description: "Identify skill gaps and create a growth roadmap.", prompt: "Help me perform a career gap analysis. Ask me my current role or stage, skills, qualifications, experience, target role, and how many years I have to get there. Compare my current profile with what the target role requires, identify my major skill gaps, and create a practical 6-month improvement plan with skills to learn, activities to practice, and a progress tracking method." },
    { id: "c9", title: "Write a Cover Letter", description: "Personalized cover letters that grab attention.", prompt: "Help me write a strong cover letter. Ask me the job title and company, my most relevant experience and skills, one specific achievement I'm proud of, and why I want this role at this company. Then write a concise, personalized cover letter under 350 words that grabs attention, shows fit, and ends with a confident call to action." },
    { id: "c10", title: "Plan a Career Change", description: "Step-by-step roadmap for switching industries.", prompt: "I want to change my career. Act as a career transition coach. Ask me my current role and industry, the new field I want to move into, my reasons for switching, my transferable skills, and any constraints. Then give me a realistic step-by-step transition plan including skills to build, roles to target first, how to network into the new field, and what to expect in the first 6 months." },
    { id: "c11", title: "Ask for a Promotion", description: "Build your case and script the conversation.", prompt: "Help me ask for a promotion. Act as a career coach. Ask me my current role, how long I've been in it, my biggest achievements, why I believe I'm ready, and any concerns I have. Then help me build a strong promotion case with specific talking points, a script for the conversation with my manager, and advice on timing and follow-up." },
    { id: "c12", title: "Build a 5-Year Career Plan", description: "Design a clear roadmap for your professional future.", prompt: "Help me build a 5-year career plan. Ask me my current role, where I ultimately want to be in 5 years, my core strengths, areas I need to develop, and any life goals that will shape my career decisions. Then create a year-by-year roadmap with key milestones, skills to acquire, experiences to seek, and habits to build each year." },
    { id: "c13", title: "Handle Workplace Politics", description: "Navigate office dynamics without compromising your values.", prompt: "Help me navigate workplace politics. Ask me about my current situation — the dynamics I'm experiencing, my role, who the key players are, and what outcome I want. Then give me a strategic guide to understanding political dynamics at work, building alliances, staying professional under pressure, and advancing without playing dirty." },
    { id: "c14", title: "Build a Freelance Profile", description: "Set up a compelling freelance presence and land clients.", prompt: "Help me build a strong freelance profile. Ask me what service I offer, my experience level, my target clients (startups, agencies, small businesses, individuals), my preferred platforms (Upwork, Fiverr, LinkedIn, personal website), and my rate range. Then help me write a compelling profile bio, define my service packages, and give me a 30-day plan to land my first 3 clients." },
    { id: "c15", title: "Prepare for a Layoff or Job Loss", description: "Handle unexpected job loss with a clear action plan.", prompt: "I have recently lost my job or am worried about a potential layoff. Act as a career coach and financial advisor. Ask me about my field, years of experience, financial runway, immediate priorities, and emotional state. Then give me a practical 30-day action plan covering job search strategy, financial steps to take immediately, how to update my professional profiles, and how to use my network effectively during this time." },
  ],
  "Skills": [
    { id: "sk1", title: "Learn Any Skill Fast", description: "Create a learning roadmap for any skill.", prompt: "I want to learn [skill]. Act as an expert learning coach. Create a 30-day learning roadmap for a complete beginner. Break it into weekly phases, recommend free resources, suggest daily practice habits, and give me one project idea to apply what I learn." },
    { id: "sk2", title: "Master Public Speaking", description: "Build confidence speaking in front of others.", prompt: "Help me become a better public speaker. Ask me about my current comfort level, the type of speaking I do, and my biggest fear. Then give me a 2-week practice plan, common mistakes to avoid, and a powerful framework for structuring any talk." },
    { id: "sk3", title: "Improve Writing Skills", description: "Write more clearly, confidently, and concisely.", prompt: "Act as a writing coach. I want to improve my writing for [context]. Give me the top 5 principles of clear, compelling writing. Then take a sample paragraph I share and rewrite it to show me how to apply these principles in practice." },
    { id: "sk4", title: "Master a New Skill in 30 Days", description: "Get a structured plan to learn anything this month.", prompt: "Help me create a plan to master a new skill. Ask me which skill, my current level, why I want to learn it, how much time I can dedicate each day or week, and any schedule constraints. Create a structured 30-day learning plan with clear daily tasks, recommended methods, a simple practice routine, and a weekly progress check." },
    { id: "sk5", title: "Improve Communication Skills", description: "Get a 7-day personalized communication plan.", prompt: "Help me improve my communication skills. Ask me a few questions to identify my biggest communication weakness — fluency, grammar, confidence, fear of speaking to strangers, public speaking, or anything else. Create a 7-day communication improvement plan with 3 practical daily exercises, 1 daily challenge, and a confidence strategy." },
    { id: "sk6", title: "Get Better at Decision Making", description: "Learn frameworks for smarter choices.", prompt: "Help me make better decisions. I'm facing a decision about [topic]. Walk me through a structured decision-making framework — list my options, help me weigh pros and cons, identify hidden assumptions, and suggest which option aligns best with my goals and values." },
    { id: "sk7", title: "Learn Critical Thinking", description: "Think sharper, argue better, avoid logical traps.", prompt: "Teach me critical thinking. Explain what it means to think critically and give me the 5 most common cognitive biases and logical fallacies — with real-life examples for each. Then give me a 3-step mental checklist I can run through any time I need to evaluate information, make a decision, or form an opinion." },
    { id: "sk8", title: "Improve My Memory", description: "Retain more of what you read, watch, and hear.", prompt: "Help me improve my memory and retention. Ask me what kinds of things I struggle to remember most and how I currently try to memorize things. Then explain the most effective science-backed memory techniques with simple examples and a 7-day practice plan." },
    { id: "sk9", title: "Develop Emotional Intelligence", description: "Understand and manage emotions — yours and others'.", prompt: "Help me develop my emotional intelligence (EQ). Explain the 5 components of EQ in simple terms. Then ask me which area I struggle with most and create a 2-week practical exercise plan to help me improve in that area, including one daily reflection habit and one social exercise per day." },
    { id: "sk10", title: "Learn Speed Reading", description: "Read faster without losing comprehension.", prompt: "Teach me how to read faster. Explain the main techniques behind speed reading — chunking, reducing subvocalization, using a pointer, active scanning. Then give me a 2-week speed reading training plan with daily 15-minute practice exercises, how to test my current WPM, and a goal to aim for." },
    { id: "sk11", title: "Develop a Growth Mindset", description: "Rewire how you think about challenges and learning.", prompt: "Help me develop a growth mindset. Ask me about a recent situation where I gave up or felt like I wasn't good enough. Then explain what a growth mindset really means, show me how my fixed mindset shows up in daily life, and give me a 2-week mindset retraining plan with daily exercises and journaling prompts." },
    { id: "sk12", title: "Learn Data Analysis Basics", description: "Start making sense of data without a technical background.", prompt: "Help me learn the basics of data analysis. Ask me my background (no technical experience, some Excel, familiar with formulas), what I want to use data analysis for (work reports, business decisions, personal projects), and how much time I can dedicate per week. Then create a beginner-friendly 4-week learning plan covering spreadsheets, basic statistics, data visualization, and one hands-on mini project." },
    { id: "sk13", title: "Improve Time Management", description: "Stop wasting time and start owning your day.", prompt: "Help me improve my time management. Ask me how I currently structure my day, what my biggest time wasters are, whether I work better in the morning or evening, and what I consistently fail to get done. Then give me a personalized time management system using techniques like time-blocking, the Pomodoro method, or the MIT (Most Important Task) approach — with a daily template I can follow starting tomorrow." },
    { id: "sk14", title: "Learn AI Tools for Work", description: "Use AI to work smarter and faster every day.", prompt: "Help me learn how to use AI tools effectively for my work. Ask me what my job or role is, what tasks take up most of my time, what tools I already use (Word, Excel, Canva, email, etc.), and what I hope AI can help me with (writing, research, summarizing, creating visuals, automating tasks). Then recommend the best AI tools for my specific workflow and give me a practical 2-week starter plan to integrate them into my daily work." },
    { id: "sk15", title: "Master Excel or Google Sheets", description: "Go from basic to confident in spreadsheets.", prompt: "Help me get better at Excel or Google Sheets. Ask me my current level (beginner: just basic data entry; intermediate: some formulas; advanced: pivot tables and macros), what I use spreadsheets for at work or personally, and what specific problems I want to solve. Then give me a skill-level-appropriate 30-day learning plan with key functions to master, practical exercises, and a mini project to apply everything." },
  ],
  "Money": [
    { id: "m1", title: "Build a Personal Budget", description: "Create a realistic budget that actually works.", prompt: "Act as a friendly personal finance coach. Help me build a monthly budget. Ask me my monthly income, fixed expenses, variable expenses, and savings goals. Then create a simple budget plan using the 50/30/20 rule and flag areas where I can cut back." },
    { id: "m2", title: "Pay Off Debt Faster", description: "Create a smart debt repayment strategy.", prompt: "I want to get out of debt faster. Act as a debt coach. Ask me to list my debts (amounts, interest rates, minimum payments). Then recommend the best repayment strategy — avalanche or snowball method — with a step-by-step monthly plan." },
    { id: "m3", title: "Start Investing as a Beginner", description: "Understand the basics of investing simply.", prompt: "I want to start investing but don't know where to begin. Explain investing in simple terms — stocks, mutual funds, index funds, and SIPs. Then, based on my monthly savings and risk tolerance (which I'll share), suggest a beginner-friendly investment plan." },
    { id: "m4", title: "Build an Emergency Fund", description: "Set up a financial safety net step by step.", prompt: "Help me build an emergency fund from scratch. Ask me my monthly expenses, current savings, and income. Then calculate how much I need for a 3–6 month emergency fund and create a realistic month-by-month savings plan." },
    { id: "m5", title: "Increase Your Income", description: "Get specific strategies to earn more money.", prompt: "Act as my income strategist. Ask me about my job, main skills, experience level, interests, how much free time I have, and my income goals. Suggest 3 specific income growth strategies suitable for my profile, recommend skills to learn to increase my earning potential, and suggest 1 high-risk high-reward option that could significantly boost my income." },
    { id: "m6", title: "Identify & Monetize Your Strengths", description: "Turn your natural talents into income opportunities.", prompt: "Help me identify my strengths and possible career directions. Ask me 10 thoughtful questions about what I enjoy doing, where I perform well, what problems I like solving, and where I naturally excel. Identify my top 3 strengths and suggest career directions that suit me, along with how these paths can be monetized or turned into income opportunities." },
    { id: "m7", title: "Plan a Major Purchase", description: "Save for big life goals with a structured plan.", prompt: "Help me plan and save for a major purchase. Ask me what I want to buy, the estimated cost, my current savings, monthly income, and timeline. Then create a step-by-step savings plan with monthly targets, tips to cut expenses, and whether I should buy outright, use EMI, or wait." },
    { id: "m8", title: "Understand Your Money Mindset", description: "Identify and shift the beliefs holding you back financially.", prompt: "Help me understand my money mindset. Ask me 8 reflective questions about how I grew up thinking about money, how I feel when I spend or save, my biggest financial fear, and my relationship with wealth. Then identify my core money belief patterns, explain how they may be helping or hurting me, and suggest 3 mindset shifts to improve my financial decisions." },
    { id: "m9", title: "Create a Savings Challenge", description: "Make saving fun with a personalized 30-day challenge.", prompt: "Create a personalized savings challenge for me. Ask me my savings goal, timeline, monthly income, current savings rate, and what has made saving difficult in the past. Then design a fun, structured savings challenge that fits my lifestyle, with weekly targets, milestone rewards, and a tracker I can follow." },
    { id: "m10", title: "Understand Tax Basics", description: "Learn how taxes work and how to optimize them legally.", prompt: "Help me understand the basics of taxes. Ask me if I'm salaried, self-employed, or a student, my country or region, and whether I'm confused about a specific area. Then explain the key tax concepts I need to know, the most common deductions I might be missing, and practical tips to reduce my tax liability legally." },
    { id: "m11", title: "Calculate My Net Worth", description: "Get a clear picture of your overall financial health.", prompt: "Help me calculate and understand my net worth. Explain what net worth is and why it matters. Then walk me through listing all my assets (savings, investments, property, valuables) and all my liabilities (loans, credit card debt, EMIs). Help me calculate the number, interpret what it means for my financial health, and suggest 3 concrete actions to improve it over the next 6 months." },
    { id: "m12", title: "Plan for Financial Independence", description: "Calculate your FI number and map out your early retirement.", prompt: "Help me plan for financial independence. Ask me my age, current monthly income and expenses, total savings and investments, target retirement age, and desired monthly lifestyle cost after retirement. Then calculate my financial independence number (FI number) using the 25x rule, show me how long it will take to reach it at my current savings rate, and suggest how I can accelerate the timeline." },
    { id: "m13", title: "Understand Mutual Funds vs FD", description: "Compare investment options to find the best fit for you.", prompt: "Help me understand the difference between mutual funds and fixed deposits (FDs) and decide which is better for my situation. Ask me my investment goal (wealth creation, safety, regular income), time horizon, risk appetite, and tax bracket. Then compare both options across return potential, risk, liquidity, and tax efficiency — and recommend which one (or what combination) suits my profile best." },
  ],
  "Social": [
    { id: "so1", title: "Start Conversations Confidently", description: "Never run out of things to say.", prompt: "Help me become better at starting and maintaining conversations. Give me 10 open-ended conversation starters for professional and social settings, tips to keep the conversation flowing naturally, advice on being a better listener, and how to gracefully exit a conversation." },
    { id: "so2", title: "Handle Difficult People", description: "Deal with conflict and tough personalities calmly.", prompt: "I'm dealing with a difficult person in my life — [describe the situation]. Act as a communication coach. Help me understand their perspective, suggest how to approach the situation calmly, and give me specific phrases to de-escalate tension and communicate assertively without being aggressive." },
    { id: "so3", title: "Make Friends as an Adult", description: "Practical advice for building genuine connections.", prompt: "I'm struggling to make friends as an adult. Give me practical, realistic advice on meeting new people and building genuine friendships. Suggest specific places to meet like-minded people, habits that make you more likable, and how to transition from acquaintance to actual friend." },
    { id: "so4", title: "Write a Heartfelt Message", description: "Craft personal messages that truly resonate.", prompt: "Help me write a heartfelt message to [person] for [occasion]. Ask me about my relationship with this person, the tone I want, and any specific memories or details to include. Then write a personal, genuine message." },
    { id: "so5", title: "Improve Your Networking Skills", description: "Build a powerful professional network without the awkwardness.", prompt: "Act as a networking coach. Help me build a stronger professional network. Ask me about my industry, career stage, and networking goals. Then give me a step-by-step strategy including how to approach people on LinkedIn, what to say at events, and how to follow up without feeling awkward." },
    { id: "so6", title: "Set Healthy Boundaries", description: "Learn to say no and protect your time and energy.", prompt: "Help me set healthy boundaries in my personal and professional life. Ask me about a specific situation where I'm struggling. Then explain why boundaries are important, help me identify what boundary I need, and give me exact words and phrases to communicate it clearly, kindly, and confidently." },
    { id: "so7", title: "Improve Your Listening Skills", description: "Become a more present and empathetic listener.", prompt: "Help me become a better listener. Explain the difference between passive and active listening, the 5 most common listening mistakes, and how to show genuine interest. Then give me a 1-week listening challenge with one small daily exercise I can practice in real conversations." },
    { id: "so8", title: "Handle Social Anxiety", description: "Manage anxiety and feel more comfortable in groups.", prompt: "I struggle with social anxiety. Ask me about the situations where I feel most anxious, what symptoms I experience, and what I've tried before. Then give me a realistic 2-week plan to gradually reduce social anxiety using exposure techniques and grounding exercises." },
    { id: "so9", title: "Improve Your Romantic Relationship", description: "Build deeper connection and handle conflict better.", prompt: "Help me improve my romantic relationship. Act as a relationship coach. Ask me about the key challenge I'm facing, how long we've been together, how we handle conflict, and what I wish was different. Then give me practical communication strategies, a conversation framework for sensitive topics, and 3 small daily habits that build deeper connection." },
    { id: "so10", title: "Reconnect With Someone", description: "Reach out to old friends or colleagues naturally.", prompt: "Help me reconnect with someone I've lost touch with. Ask me who this person is, how long it's been, why we lost touch, and what I hope to rekindle. Then write a warm, natural message I can send that doesn't feel forced or awkward, along with tips on how to rebuild the connection over time." },
    { id: "so11", title: "Repair a Damaged Relationship", description: "Take the first step toward healing a rift.", prompt: "I have a damaged relationship with someone important to me — [describe the situation briefly]. Act as a relationship coach. Ask me what happened, how long the rift has lasted, what I've tried already, and what outcome I want. Then help me understand my role in the conflict, guide me on whether to reach out or wait, and give me a thoughtful, sincere message I can send to start the repair process." },
    { id: "so12", title: "Become a Better Parent", description: "Age-appropriate strategies for stronger family bonds.", prompt: "Help me become a better parent. Act as a family and child development coach. Ask me about my child's age, the specific challenge I'm facing (tantrums, screen time, communication, school stress, teen conflict), and how I've been handling it. Then give me age-appropriate strategies, better ways to communicate with my child, and 3 daily habits that will strengthen our bond over time." },
    { id: "so13", title: "Handle a Family Conflict", description: "Navigate complex family dynamics with empathy.", prompt: "I'm dealing with a conflict in my family — [describe the situation]. Act as a family counselor. Ask me who's involved, the history of the issue, what's been tried, and what outcome I hope for. Then help me understand the underlying dynamics, suggest how to approach each person involved, and give me a practical step-by-step plan to bring the family back to a healthier place." },
  ],
  "Goals": [
    { id: "g1", title: "Set SMART Goals", description: "Define goals that are clear and achievable.", prompt: "Help me set a SMART goal. I want to achieve [goal]. Walk me through making this goal Specific, Measurable, Achievable, Relevant, and Time-bound. Then break it into monthly and weekly milestones, suggest how to track my progress, and identify potential obstacles and how to overcome them." },
    { id: "g2", title: "Build a Habit That Sticks", description: "Use science-backed methods to form lasting habits.", prompt: "I want to build the habit of [habit]. Act as a habit coach using principles from behavioral science. Create a 21-day habit-building plan with a daily schedule, accountability tips, and advice on what to do when I miss a day." },
    { id: "g3", title: "Do a Life Audit", description: "Evaluate 8 key areas of your life and find focus.", prompt: "Help me do a comprehensive life audit. Take me through 8 key areas: health, career, finances, relationships, personal growth, fun, environment, and purpose. For each, ask me to rate my satisfaction out of 10 and explain why. Then identify my top 3 focus areas and suggest one action for each." },
    { id: "g4", title: "Stay Motivated Long-Term", description: "Maintain momentum even when the initial excitement fades.", prompt: "I'm losing motivation to keep working toward my goal of [goal]. Act as a motivational coach. Help me reconnect with my 'why', reframe setbacks as learning opportunities, and give me 5 practical strategies to maintain momentum. Also suggest a weekly review ritual to keep me on track." },
    { id: "g5", title: "Accelerate Goal Achievement", description: "A detailed 90-day execution plan for your biggest goals.", prompt: "Help me accelerate progress towards an important goal. Ask me what the goal is, why it matters, my current starting point, the resources I already have, and the main obstacles I might face. Create a detailed 90-day execution plan broken into monthly milestones, weekly priorities, and daily tasks. Also include a short tracking method to monitor progress." },
    { id: "g6", title: "Productivity Coach", description: "Get a personalized daily time block plan and routine.", prompt: "Act as my productivity coach. Ask me 5 questions to understand my goals, daily routine, schedule, work or study commitments, and biggest distractions. Create a practical daily time block plan, suggest strategies to avoid distractions, and create a simple 15-minute daily improvement routine." },
    { id: "g7", title: "Break a Bad Habit", description: "Use behavioral science to replace unhealthy behaviors.", prompt: "I want to break the habit of [bad habit]. Act as a behavioral coach. Ask me how long I've had this habit, what triggers it, how it makes me feel, and what I've already tried. Then explain the psychology behind why this habit is hard to break, and give me a science-backed 3-week plan to gradually replace it with a healthier behavior." },
    { id: "g8", title: "Design Your Ideal Week", description: "Create a balanced weekly template for work and life.", prompt: "Help me design my ideal week. Ask me about my work hours, personal priorities (health, relationships, hobbies, learning), how much rest I need, and what a truly fulfilling week looks like. Then create a realistic hour-by-hour weekly template across 7 days that balances productivity, rest, and meaning." },
    { id: "g9", title: "Do a Monthly Review", description: "Reflect on your month and plan the next with intention.", prompt: "Help me do a thorough monthly review. Take me through: 1) Wins and accomplishments this month, 2) Things that didn't go as planned and why, 3) What I learned about myself, 4) A score out of 10 for key life areas, 5) What I want to do differently next month, and 6) My top 3 priorities for the coming month. Help me reflect honestly and plan with intention." },
    { id: "g10", title: "Create an Accountability System", description: "Design a ritual to stay consistent with your goals.", prompt: "Help me create a personal accountability system. Ask me what goal or habit I'm trying to stay consistent with, what has caused me to fall off track before, whether I prefer solo accountability or a partner, and how often I want to check in. Then design a complete accountability system with a daily check-in method, weekly review ritual, and a simple consequence/reward structure to keep me honest." },
    { id: "g11", title: "Write a Personal Mission Statement", description: "Define your north star for life decisions.", prompt: "Help me write a personal mission statement. Ask me what I value most in life, how I want to contribute to the world, what kind of work or activities make me feel most alive, and how I want to be remembered. Then help me craft a clear, authentic, and inspiring personal mission statement in 1–3 sentences that I can use as a north star for every decision I make." },
    { id: "g12", title: "Build a Reading Habit", description: "Create a system to read more and remember what you learn.", prompt: "Help me build a consistent reading habit. Ask me how many books I want to read this year, how much time I can realistically read per day, what genres or topics I enjoy, and what's stopped me from reading consistently in the past. Then create a personalized reading system with a daily reading schedule, tips to pick books I'll actually finish, and a method to remember and apply what I read." },
    { id: "g13", title: "Create a Vision Board Plan", description: "Clarify your vision and connect with it daily.", prompt: "Help me create a meaningful vision board. Ask me about my goals across 5 life areas: career, relationships, health, lifestyle, and personal growth. For each area, help me clarify exactly what I want and why. Then guide me on how to create an effective vision board — digital or physical — with specific image categories, affirmations to include, and a daily practice to connect with it so it actually drives my behavior." },
  ],
  "Creativity": [
    { id: "cr1", title: "Beat Creative Block", description: "Unlock ideas when you feel stuck.", prompt: "I'm experiencing creative block with my [project]. Act as a creative coach. Use techniques like mind mapping, random word association, or the 'worst idea first' method to help me generate at least 10 fresh ideas. Then help me pick the most promising one to develop further." },
    { id: "cr2", title: "Write a Compelling Story", description: "Build a story with strong characters and plot.", prompt: "Help me write a short story. Ask me about the genre, main character, setting, and central conflict. Then help me outline a 3-act structure, develop the protagonist's arc, and suggest a memorable opening line and satisfying ending." },
    { id: "cr3", title: "Come Up With Business Ideas", description: "Brainstorm tailored business or side hustle concepts.", prompt: "Help me brainstorm business ideas. Ask me about my skills, interests, available time per week, starting budget, and preference for online or offline. Then generate 7 business or side hustle ideas tailored to me — for each, briefly explain the concept, target customer, and how to get the first paying customer." },
    { id: "cr4", title: "Name Your Brand or Project", description: "Generate creative names for your next big thing.", prompt: "Help me name my [brand / product / project / podcast]. Ask me about the vibe I want, the target audience, and any words or themes I love or want to avoid. Then generate 15 creative name ideas with a short explanation for each." },
    { id: "cr5", title: "Write Social Media Content", description: "Create a 7-day content calendar with captions.", prompt: "Act as a social media content strategist. Ask me about my niche, target audience, platform, and content goal. Then create a 7-day content calendar with post ideas, captions, and relevant hashtags for each day." },
    { id: "cr6", title: "Build Your Personal Brand", description: "Define your positioning and growth action plan.", prompt: "Help me build my personal brand. Ask me about my expertise, values, target audience, what makes me different, and what I want to be known for. Then help me define my brand positioning statement, suggest content pillars, and give me a 30-day action plan to grow my personal brand online." },
    { id: "cr7", title: "Write a Poem or Spoken Word", description: "Express themes or emotions through powerful verse.", prompt: "Help me write a poem or spoken word piece. Ask me about the theme or emotion I want to express, the tone, and whether I want it to rhyme or be free verse. Then write a powerful, original piece and explain the stylistic choices you made." },
    { id: "cr8", title: "Develop a Content Strategy", description: "Build a loyal audience with a 30-day strategy.", prompt: "Help me develop a content strategy. Ask me about my platform, niche, target audience, content goal, and how much time I can dedicate per week. Then create a 30-day content strategy with content pillars, posting frequency, format recommendations, and tips to build a loyal audience over time." },
    { id: "cr9", title: "Write a YouTube Script", description: "Craft scripts with hooks, transitions, and CTAs.", prompt: "Help me write a YouTube video script. Ask me the topic, my target audience, video length, channel niche, and the goal of the video. Then write a complete script with a strong hook in the first 30 seconds, clear sections, transitions, and a compelling call to action at the end." },
    { id: "cr10", title: "Develop a Side Project Idea", description: "Validate and plan your MVP in 60 days.", prompt: "Help me develop a side project idea into something real. Ask me about the idea I have in mind, the problem it solves, who it's for, what skills I have, how much time I can give per week, and my goal. Then help me validate the idea, define the simplest first version (MVP), create a 60-day build plan, and identify the first 3 actions I should take this week." },
    { id: "cr11", title: "Write a Newsletter Edition", description: "Draft engaging emails with subject lines and CTAs.", prompt: "Help me write an edition of my email newsletter. Ask me the topic or theme of this edition, my audience (who subscribes and why), the tone I want (educational, conversational, inspiring, entertaining), and any specific updates or stories I want to include. Then write a complete newsletter edition with a catchy subject line, opening hook, main content section, a brief personal note or insight, and a clear call to action." },
    { id: "cr12", title: "Design a Logo Concept Brief", description: "Create a professional brief for designers or AI tools.", prompt: "Help me create a logo design brief. Ask me about my brand name, what the business does, the target audience, the feeling I want the logo to evoke (trustworthy, playful, bold, minimal, luxurious), preferred colors if any, styles I like (wordmark, icon, combination), and any logos I admire. Then write a detailed, professional design brief I can hand to a designer or use with an AI design tool like Looka or Canva." },
    { id: "cr13", title: "Plan a Creative Project from Scratch", description: "Map out phases and milestones for any creative work.", prompt: "Help me plan a creative project from scratch. Ask me what the project is (short film, book, podcast, art series, music album, design collection), my goal for it (personal expression, portfolio, audience growth, income), my timeline, available resources, and any blockers I'm worried about. Then create a complete project plan with phases, milestones, a weekly work schedule, and advice on how to stay creative while hitting deadlines." },
  ],
  "Quick Help": [
    { id: "q1", title: "Summarize Anything", description: "Get a clear summary of any text or topic.", prompt: "Please summarize the following in simple, clear language. Give me: 1) A 3-sentence overview, 2) The 5 most important points as bullet points, and 3) One key takeaway I should remember. Here is the content: [paste your text or describe the topic here]." },
    { id: "q2", title: "Explain Like I'm 5", description: "Get a super simple explanation of any concept.", prompt: "Explain [concept / topic] to me as if I'm a complete beginner with no prior knowledge. Use a simple analogy, avoid jargon, and keep it under 150 words. Then tell me the one most important thing I should understand and suggest what I should learn next." },
    { id: "q3", title: "Fix My Email or Message", description: "Improve clarity, tone, and grammar of any text.", prompt: "Please improve the following message. Make it clearer, more professional (or friendly — I'll tell you the tone), and fix any grammar issues. Keep the original intent intact. Here's the original: [paste your message]. Also briefly explain the main changes you made and why." },
    { id: "q4", title: "Give Me a Second Opinion", description: "Get unbiased perspectives and identify blind spots.", prompt: "I need an unbiased second opinion on this situation: [describe your situation]. Please: 1) Summarize what I've shared to confirm you understand, 2) Point out any blind spots I might be missing, 3) Give me 2–3 different perspectives, and 4) Suggest what you'd consider if you were in my position." },
    { id: "q5", title: "Create a Bio for Yourself", description: "Generate bios for LinkedIn, Instagram, and resumes.", prompt: "Ask me a series of questions to understand my skills, experience, interests, achievements, and what I want to be known for professionally. Ask the questions one at a time. After collecting enough information, create: 1) A professional LinkedIn bio, 2) A short and engaging Instagram bio, 3) A single powerful one-line statement I can use in my resume." },
    { id: "q6", title: "Turn Any Topic Into a Quiz", description: "Test your knowledge with an interactive quiz.", prompt: "Act as a quiz master. I want to test my knowledge on [topic]. Create a quiz with 10 questions of increasing difficulty. After I answer each question, tell me if I'm right or wrong, explain the correct answer briefly, and keep a score tally. At the end give me a final score and suggest what I should study more." },
    { id: "q7", title: "Build a Reading List", description: "Get personalized book recommendations for your goals.", prompt: "Act as a book curator. Ask me about my current goals, interests, topics I want to learn about, how much I read per week, and whether I prefer practical or big-idea books. Then recommend 8 books suited to me — for each, share the title, author, one-line summary, and why it's right for me specifically." },
    { id: "q8", title: "Roast My Idea", description: "Stress-test your ideas with honest, sharp criticism.", prompt: "I have an idea I want to stress-test: [describe your idea]. Act as a sharp, honest critic. Point out every weakness, flaw, assumption, and risk. Then tell me what would need to be true for this idea to actually work. End with 3 questions I must be able to answer before moving forward." },
    { id: "q9", title: "Write a Speech or Toast", description: "Draft memorable speeches for any occasion.", prompt: "Help me write a speech or toast. Ask me the occasion, my relationship to the audience and person being honored, the tone I want, and the time limit. Then write a complete, memorable speech that opens with impact, includes a personal story, and closes with a line people will remember." },
    { id: "q10", title: "Plan a Trip Itinerary", description: "Get a day-by-day travel plan with hidden gems.", prompt: "Help me plan a trip itinerary. Ask me where I'm going, how many days I have, my budget level, the type of traveler I am, and who I'm traveling with. Then create a day-by-day itinerary with top places to visit, where to eat, travel tips, and one hidden gem per day." },
    { id: "q11", title: "Draft a Complaint or Feedback", description: "Write effective messages to resolve issues.", prompt: "Help me write a complaint or feedback message. Ask me what the issue is, who it's addressed to, what outcome I want, and the tone I want. Then write an effective message that clearly states the problem, the impact on me, and what I expect as a resolution." },
    { id: "q12", title: "Explain Any News or Concept", description: "Get a neutral, simple breakdown of complex topics.", prompt: "Help me understand [news story / concept / topic]. Break it down for me: 1) What is this about in simple terms, 2) Why does it matter, 3) Who are the key players or sides involved, 4) What happened leading up to this, and 5) What might happen next. Use neutral language and avoid bias." },
    { id: "q13", title: "Write a Resignation Letter", description: "Draft a professional and gracious exit letter.", prompt: "Help me write a resignation letter. Ask me my current role, the company, how much notice I'm giving, whether I want to state my reason for leaving, and the tone I want. Then write a professional resignation letter that's gracious, clear, and leaves the door open for future connections." },
    { id: "q14", title: "Help Me Apologize", description: "Craft sincere apologies that take full responsibility.", prompt: "Help me write a genuine, effective apology. Ask me who I'm apologizing to, what I did or said that caused harm, the impact it had on the other person, and what I want the outcome to be (repair the relationship, clear the air, take responsibility). Then write a heartfelt, non-defensive apology that acknowledges the mistake, takes full responsibility, and ends with a sincere commitment to do better." },
    { id: "q15", title: "Write My Instagram Bio", description: "Get 3 different versions of your perfect bio.", prompt: "Help me write a great Instagram bio. Ask me what I do or create, who my ideal follower is, the vibe I want to give off (funny, inspiring, professional, personal), any specific things I want to highlight (profession, location, passion, CTA), and whether I want emojis or a clean text-only style. Then write 3 different versions of my Instagram bio so I can choose the one that feels most like me." },
  ],
  "Image & Video": [
    { id: "iv1", title: "Generate AI Image Prompts", description: "Create detailed prompts for Midjourney, DALL-E, and more.", prompt: "Help me write a highly detailed prompt for an AI image generator (like Midjourney or DALL-E). Ask me about the subject, style (photorealistic, oil painting, 3D render, etc.), lighting, camera angle, and mood. Then write 3 variations of a professional prompt that will get the best results." },
    { id: "iv2", title: "Design a Photo Shoot", description: "Plan themes, locations, and shot lists for your next shoot.", prompt: "Help me plan a professional photo shoot. Ask me about the theme, the subject (person, product, event), the location, and the desired mood. Then create a detailed shot list, suggest lighting setups, and give me 3 tips for directing the subject." },
    { id: "iv3", title: "Edit Photos Like a Pro", description: "Get step-by-step editing guides for any aesthetic.", prompt: "I want to edit my photos to achieve a specific look. Ask me what software I'm using (Lightroom, Photoshop, mobile apps), the current state of my photo, and the aesthetic I want (vintage, high-contrast, airy, moody). Then give me a step-by-step editing guide with specific slider adjustments." },
    { id: "iv4", title: "Create a Mood Board", description: "Visual inspiration and color palettes for your projects.", prompt: "Help me create a visual mood board for a new project. Ask me about the project's purpose, the target audience, and the core emotions I want to convey. Then suggest a color palette, 5 specific image themes to search for, and 3 textures or patterns that fit the vibe." },
    { id: "iv5", title: "Product Photography Guide", description: "Make your products look high-end with simple setups.", prompt: "Help me take better product photos for my business. Ask me what the product is, what equipment I have (smartphone, DSLR, natural light, studio lights), and where I'll be sharing the photos. Then give me a simple setup guide, 3 creative composition ideas, and tips for making the product look high-end." },
    { id: "iv6", title: "Portrait Lighting Setup", description: "Master Rembrandt, butterfly, and split lighting techniques.", prompt: "Help me set up lighting for a portrait. Ask me about the mood I want (dramatic, soft, professional, edgy) and what lights I have available. Then explain a specific lighting technique (like Rembrandt, butterfly, or split lighting) and how to position the lights and subject." },
    { id: "iv7", title: "Architectural Photo Plan", description: "Capture buildings and interiors with the best angles.", prompt: "Help me photograph a building or interior space. Ask me about the location, the time of day, and whether it's an interior or exterior shot. Then give me a plan covering the best angles, how to handle challenging lighting, and what lens or settings to prioritize." },
    { id: "iv8", title: "Macro Photography Tips", description: "Get sharp, detailed shots of tiny subjects.", prompt: "Help me get started with macro photography. Ask me what I want to photograph (flowers, insects, textures) and what gear I'm using. Then give me a guide on achieving sharp focus, managing depth of field, and finding the best natural light for tiny subjects." },
    { id: "iv9", title: "Vintage Photo Aesthetic", description: "Recreate classic film looks in your digital photos.", prompt: "Help me recreate a vintage film look in my photography. Ask me which era or film stock I'm inspired by (70s polaroid, 90s disposable, classic B&W). Then give me tips on how to shoot for that look and how to post-process the images to add grain, light leaks, and authentic colors." },
    { id: "iv10", title: "Abstract Art Concepts", description: "Brainstorm creative techniques for abstract visuals.", prompt: "Help me brainstorm ideas for abstract digital art or photography. Ask me about my preferred tools (camera, Procreate, Photoshop) and the themes I'm interested in (fluidity, geometry, light). Then generate 5 creative concepts with specific techniques to try." },
    { id: "iv11", title: "Script a YouTube Video", description: "Structure your content for high retention and engagement.", prompt: "Help me write a script for a YouTube video. Ask me the topic, target audience, and the main goal of the video. Then create a structured script with a high-retention hook, clear body sections, transitions, and a strong call to action." },
    { id: "iv12", title: "Plan a Viral Short/Reel", description: "Hooks and visual cues for TikTok and Instagram Reels.", prompt: "Help me plan a short-form video for TikTok or Instagram Reels. Ask me about the trend or topic, the target audience, and the key message. Then give me a 15-30 second storyboard with a '3-second hook', visual cues, and text overlay suggestions." },
    { id: "iv13", title: "Create a Video Storyboard", description: "Scene-by-scene breakdowns for your video projects.", prompt: "Help me storyboard a video project. Ask me about the story or message, the total length, and the key scenes. Then create a scene-by-scene breakdown with visual descriptions, audio/voiceover cues, and suggested camera movements for each shot." },
    { id: "iv14", title: "Video Editing Workflow", description: "Organize your editing process from rough cut to export.", prompt: "Help me organize my video editing process. Ask me about the type of video, the software I'm using, and how much footage I have. Then give me a step-by-step workflow from importing and rough cutting to color grading and final export." },
    { id: "iv15", title: "Cinematic B-Roll List", description: "Atmospheric shots to make your edits look professional.", prompt: "Help me capture cinematic B-roll for my video. Ask me about the main subject and the overall vibe of the video. Then give me a list of 10 specific B-roll shots (wide, tight, movement, detail) that will make the final edit look professional and atmospheric." },
    { id: "iv16", title: "Interview Video Setup", description: "Framing, lighting, and audio for professional interviews.", prompt: "Help me set up a professional-looking video interview. Ask me about the location, the number of people, and the equipment I have. Then give me a guide on framing (rule of thirds), lighting (3-point setup), and how to ensure high-quality audio." },
    { id: "iv17", title: "Travel Vlog Structure", description: "Tell a compelling story about your latest journey.", prompt: "Help me structure a travel vlog that people actually want to watch. Ask me where I went and the highlights of the trip. Then create a narrative flow that mixes storytelling, information, and cinematic montages, including a compelling intro and outro." },
    { id: "iv18", title: "Cooking Video Flow", description: "Visual storytelling for recipes and tutorials.", prompt: "Help me plan a cooking or recipe video. Ask me what I'm making and the style of the video (ASMR, educational, fast-paced). Then give me a visual flow from the 'hero shot' intro to the step-by-step process and the final tasting." },
    { id: "iv19", title: "Tech Review Framework", description: "Balanced structures for hardware and software reviews.", prompt: "Help me structure a high-quality tech review video. Ask me what product I'm reviewing and who the audience is. Then give me a framework covering: The Hook, Specs vs. Experience, Pros & Cons, The 'Who is this for?' section, and a Final Verdict." },
    { id: "iv20", title: "Animation Scene Plan", description: "Key poses and timing for 2D or 3D animation.", prompt: "Help me plan a scene for an animation project. Ask me about the characters, the action taking place, and the emotional tone. Then provide a breakdown of the key poses, timing suggestions, and background details to make the scene come alive." },
  ],
};
